NULL,NULL,NULL,NULL,NULL,'Центральная Азия|Селебе','','',NULL,NULL,NULL,'',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'',NULL,NULL,NULL,'',NULL,NULL,'',30),(2021,0,'','A stunning sword from Bhutan with repousse silver fittings.\nThis fine example measures 83cms long in its scabbard, approx 80cms out with a blade length just under 68cms.\nThe silver work on this example is very striking and extremely well executed on all surfaces. To the front panels of the scabbard\'s fittings there are two five clawed dragons, one on each fitting. The dragons are seen writhing through broken clouds and are surrounded with checkered and floral borders.\nThe reverse of these fittings show mountains, clouds and auspicious symbols.\nThe hilt again shows important Bhutanese symbology and key relief patterning.\nThe blade is a thick heavy fighting type with a prominent hairpin pattern.\nTo the hilt is attached a very old fabric auspicious endless knot.\nA very rare sword. With the bearing of five clawed dragons and many important auspicious symbols, is mostly likely unique and made for a person of high importance.\n\nPlease note, all items with the Gallery page are examples from my personal collections. These items are not currently offered for sale but are sometimes released to the For Sale page as tastes and items vary.','','Меч з Бутану','Меч из Бутана','stunning sword from Bhutan','','','80','68','','','','','Бутан','','','','','','','','','','','','Є фото (папка Бутан)','',30),(2022,0,'','','','','Vietnamese sword','','','','','','','','','','','','','','','','','','','','','','Є фото - Vietnamese sword','',28),(2024,0,'','','','Булгарська шабля','Bulgarian medieval sabr','Булгарская сабля','','','','','','','','','Болгарія','10-11','','','','','','','','','','','Balkan correspondents- Bulgarian medieval sabre, dated 10th-11th century. The original is found near the village of Yarebitsa, north-east Bulgaria..jpg','',28),(2025,0,'','','','','Espada of Afonso Henriques','','','','','','','','','','','','','','','','','','','','','','Espada of Afonso Henriques.jpg','',14),(2026,0,NULL,NULL,NULL,NULL,NULL,'Індія-Непал-Пакистан|Ram-Dao','','',NULL,NULL,NULL,'',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'',NULL,NULL,NULL,'',NULL,NULL,'',30),(2027,0,NULL,NULL,NULL,NULL,NULL,'Індія-Непал-Пакистан|Адъяр катти','','',NULL,NULL,NULL,'',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'',NULL,NULL,NULL,'',NULL,NULL,'',30),(2028,0,NULL,NULL,NULL,NULL,NULL,'Індія-Непал-Пакистан|АТИЛЛ','','',NULL,NULL,NULL,'',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'',NULL,NULL,NULL,'',NULL,NULL,'',30),(2029,0,NULL,NULL,NULL,NULL,NULL,'Індія-Непал-Пакистан|Бане','','',NULL,NULL,NULL,'',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'',NULL,NULL,NULL,'',NULL,NULL,'',30),(2030,0,NULL,NULL,NULL,NULL,NULL,'Індія-Непал-Пакистан|Бхелхета','','',NULL,NULL,NULL,'',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'',NULL,NULL,NULL,'',NULL,NULL,'',30),(2031,0,NULL,NULL,NULL,NULL,NULL,'Індія-Непал-Пакистан|Зафар такех','','',NULL,NULL,NULL,'',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'',NULL,NULL,NULL,'',NULL,NULL,'',30),(2032,0,NULL,NULL,NULL,NULL,NULL,'Індія-Непал-Пакистан|КУНДА','','',NULL,NULL,NULL,'',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'',NULL,NULL,NULL,'',NULL,NULL,'',30),(2034,0,'-','-','Кханда – индийский меч, который часто называют палашом за немного изогнутую рукоять, которая встречается у некоторых экземпляров. Кханда представляет собой прямой обоюдоострый меч, общей длинной 90-100 сантиметров, с обоюдоострой или полуторной заточкой. Клинок кханды прямой, немного расширяется к концу, который очень часто скруглён, хотя встречаются мечи с острым треугольным концом, годным для укола. В поперечном сечении клинок линзовидный или ромбический. Гарда меча может отличаться некоторым разнообразием – от корзинчатой, до типично сабельной. Для всех кханд характерно дисковидное навершие рукоятки и длинный шип, выходящий из навершия. Этот шип – характерный признак классической кханды, но встречается он не всегда. Само слово «кханда» с санскрита переводится, как «меч». Иногда для обозначения разных типов кханд ещё используют названия фиранги и патисса.','-','-','Індія-Непал-Пакистан|Кханда (кунда)','-','-','-','-','-','-','-','-','-','-','-','-','-','-','-','-','-','-','-','-','-','-',30),(2035,0,NULL,NULL,NULL,NULL,NULL,'Індія-Непал-Пакистан|Кхора','','',NULL,NULL,NULL,'',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'',NULL,NULL,NULL,'',NULL,NULL,'',30),(2036,0,NULL,NULL,NULL,NULL,NULL,'Індія-Непал-Пакистан|маратхский меч','','',NULL,NULL,NULL,'',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'',NULL,NULL,NULL,'',NULL,NULL,'',30),(2037,0,NULL,NULL,NULL,NULL,NULL,'Індія-Непал-Пакистан|ПАМДАО','','',NULL,NULL,NULL,'',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'',NULL,NULL,NULL,'',NULL,NULL,'',30),(2038,0,NULL,NULL,NULL,NULL,NULL,'Індія-Непал-Пакистан|Пата (пуддха)','','',NULL,NULL,NULL,'',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'',NULL,NULL,NULL,'',NULL,NULL,'',30),(2039,0,NULL,NULL,NULL,NULL,NULL,'Індія-Непал-Пакистан|Пулиянкам','','',NULL,NULL,NULL,'',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'',NULL,NULL,NULL,'',NULL,NULL,'',30),(2040,0,'','','','Сосунпата, Соссун Пата, Сосун паттах','','Індія-Непал-Пакистан|Соссун Пата (Сосун паттах)','','','','','','','','','','','',NULL,NULL,NULL,'15',NULL,NULL,NULL,'25','','','',30),(2041,0,NULL,NULL,NULL,NULL,NULL,'Індія-Непал-Пакистан|Тулвар','','',NULL,NULL,NULL,'',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'',NULL,NULL,NULL,'',NULL,NULL,'',30),(2042,0,'-','-','-','-','-','Індія-Непал-Пакистан|Уруми','-','-','-','-','-','-','-','-','-','-','-','-','-','-','-','-','-','-','-','-','Распространён в северной части Малабара. Представляет собой несколько обоюдоострых полос длиной до 1,5 метра чрезвычайно гибкой стали, прикреплённых к деревянной рукояти. Существуют варианты в виде одной полосы \n','-',30),(2043,0,NULL,NULL,NULL,NULL,NULL,'Індія-Непал-Пакистан|ФИРАНГИ','','',NULL,NULL,NULL,'',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'',NULL,NULL,NULL,'',NULL,NULL,'